SELECT /* ptnrMgmtMapper.ptnrMgmtLinkList */ PARTNER_ID /*제휴사아이디 */ , IF_NO /*인터페이스 아이디 */ , UP_DIR /*파일업로드경로 */ , DOWN_DIR /*파일다운로드경로 */ , IF_RULE /*연동주기 */ , MEMO /*메모 */ , REGST_ID /*등록자아이디 */ , REGST_DTTM /*등록일시 */ , RVISN_ID /*수정자아이디 */ , RVISN_DTTM /*수정일시 */ FROM MSP_PARTNER_SUB WHERE 1 = 1
AND PARTNER_ID = #{partnerId, jdbcType=VARCHAR}
AND IF_NO = #{ifNo, jdbcType=VARCHAR}

