INSERT INTO MSP_PARTNER_MST (
		PARTNER_ID
		, PARTNER_NM
		, MANAGER_NM
		, CONTACT_NUM
		, EMAIL
		, STRT_DATE
		, END_DATE
		, MEMO
		, PARTNER_LINK_ID
		, USE_YN
		, REGST_ID
		, REGST_DTTM
) VALUES (
		  LOWER(#{partnerId, jdbcType=VARCHAR})
		, #{partnerNm, jdbcType=VARCHAR}
		, #{managerNm, jdbcType=VARCHAR}
		, #{contactNum, jdbcType=VARCHAR}
		, #{email, jdbcType=VARCHAR}
		, TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
		, '99991231235959'
		, #{memo, jdbcType=VARCHAR}
		, #{partnerLinkId, jdbcType=VARCHAR}
		, #{useYn, jdbcType=VARCHAR}
		, #{sessionUserId}
		, SYSDATE
)

