mapper.select:
/* PtnrMgmtMapper.ptnrRateList */ SELECT MST.RATE_CD , RAT.RATE_NM , MST.PARTNER_ID AS PTNR_ID , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0243' AND USG_YN = 'Y' AND CD_VAL = MST.PARTNER_ID) AS PTNR_NM , RAT.RATE_TYPE , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0047' AND USG_YN = 'Y' AND CD_VAL = RAT.RATE_TYPE) AS RATE_TYPE_NM , RAT.DATA_TYPE , RAT.BASE_AMT , MST.POINT_TYPE , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0060' AND USG_YN = 'Y' AND CD_VAL = MST.POINT_TYPE) AS POINT_TYPE_NM , MST.POINT_VAL , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0242' AND USG_YN = 'Y' AND CD_VAL = MST.USE_YN) AS USE_YN , TO_CHAR(TO_DATE(MST.STRT_DATE,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS STRT_DATE , TO_CHAR(TO_DATE(MST.END_DATE,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS END_DATE , FN_GET_USRNM(MST.RVISN_ID) AS USR_NM FROM MSP_RATE_MST RAT , MSP_PARTNER_RATE_MST MST WHERE RAT.PAY_CL_CD = 'PO' AND RAT.SERVICE_TYPE = 'P' AND MST.RATE_CD = RAT.RATE_CD
AND MST.PARTNER_ID = #{ptnrId, jdbcType=VARCHAR}
AND MST.POINT_TYPE = #{pointType, jdbcType=VARCHAR}
AND RAT.RATE_NM LIKE '%'||#{rateNm, jdbcType=VARCHAR}||'%'
AND MST.USE_YN = #{useYn, jdbcType=VARCHAR}
ORDER BY RAT.RATE_NM DESC, MST.POINT_TYPE DESC, MST.STRT_DATE DESC

