/* PtnrMgmtMapper.ptnrRateUpdate */
UPDATE  MSP_PARTNER_RATE_MST
   SET  STRT_DATE = TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
      , POINT_VAL = #{pointVal, jdbcType=VARCHAR}
      , USE_YN = #{useYn, jdbcType=VARCHAR}
      , RVISN_ID = #{sessionUserId, jdbcType=VARCHAR}
      , RVISN_DTTM = SYSDATE
 WHERE  RATE_CD = #{rateCd, jdbcType=VARCHAR}
   AND  POINT_TYPE = #{pointType, jdbcType=VARCHAR}

